}
.postcards-parent-loading-container{
    position: relative;
    top: 90px;
    display: flex;
    justify-content: center;
    align-items: center;
    flex-direction: column;
    width: 100%;
    height: 100vh;
}
.loading-newsfeed-bg{
    display: flex;
    justify-content: center;
    align-items: center;
    width: 100%;
    height: 100%;
}
.jounral-view-image{
    width: 400px;
    height: auto;
}
.inview{
    display: flex;
    justify-content: center;
