}

/* ── Content (title + text) ── */
.content-container{
    display: flex;
    flex-direction: column;
    justify-content: flex-start;
    align-items: flex-start;
    user-select: none;
    gap: 0.5rem;
}
.feed-text-content-container{
    display: flex;
    flex-direction: column;
    width: 100%;
    height: 100%;
    justify-content: flex-start;
    align-items: flex-start;
    gap: 0.35rem;
}
.feed-title-content{
    display: flex;
    justify-content: center;
    align-items: center;
}
