    justify-content: flex-start;
    gap: 0.45rem;
}
.feed-title{
    margin: 0;
    padding: 0;
    font-family: "Lexend Deca", sans-serif;
    font-size: 1.1rem;
    font-weight: 700;
    line-height: 1.45;
    letter-spacing: -0.025rem;
