.comment-button:hover{
    background-color: rgba(107, 143, 113, 0.12);
}
.comment-button:hover .svg-comment path{
    fill: var(--accent-sage);
}
.bookmark-button:hover{
    background-color: rgba(245, 158, 11, 0.12);
}
.bookmark-button:hover .svg-bookmark path{
    fill: var(--accent-amber);
}

/* ── Reading time pill ── */
.reading-time-container{
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.2rem 0.7rem;
    background-color: var(--bg-pill);
    border: 1px solid var(--border-card);
    border-radius: 10px;
    margin-left: auto;
}
.reading-time-text{
    padding: 0;
    margin: 0;
    font-family: var(--font-ui);
    font-size: 0.62rem;
    font-weight: 550;
    color: var(--accent-sage);
    letter-spacing: 0.01rem;
}

.sample-content-show{
    width: 100%;
    height: 100%;
    background-color: var(--bg-primary);
    z-index: 10;
}

/* ── Mobile responsive ── */
@media (max-width: 480px){
    .feed-search-shell{
        display: none;
    }
    .search-shell{
        top: 56px;
    }
    .search-top-bar{
        padding: 0.5rem 0.5rem 0.55rem 0.5rem;
        gap: 0.4rem;
    }
    .search-input{
        font-size: 0.8rem;
        padding: 0.5rem 0.75rem 0.5rem 2.1rem;
        border-radius: 8px;
    }
    .search-icon{
        left: 0.7rem;
        width: 14px;
        height: 14px;
    }
    .search-clear-btn{
        font-size: 0.64rem;
        padding: 0.32rem 0.52rem;
        border-radius: 6px;
    }
    .search-freedom-wall-btn{
        font-size: 0.6rem;
        padding: 0.3rem 0.45rem;
        border-radius: 6px;
    }
    .search-mode-pill{
        font-size: 0.58rem;
        padding: 0.28rem 0.44rem;
        border-radius: 6px;
    }
    .search-gallery-hint{
        margin: 0 0.5rem 0.42rem 0.5rem;
        font-size: 0.6rem;
        padding: 0.3rem 0.5rem;
        border-radius: 6px;
    }
    .search-suggestions-dropdown{
        left: 0.5rem;
        right: 0.5rem;
        top: calc(100% - 0.1rem);
        max-height: 260px;
        border-radius: 8px;
    }
    .search-suggestion-item{
        padding: 0.52rem 0.7rem;
        border-left-width: 2px;
    }
    .search-suggestion-title{
        font-size: 0.76rem;
    }
    .search-suggestion-meta{
        font-size: 0.62rem;
    }
    .postcards-parent-container {
        position: relative;
        top: 60px;
        display: flex;
        flex-direction: column;
        align-items: center;
        width: 100%;
        margin-bottom: 1rem;
        gap: 12px;
        padding: 0 10px;
        box-sizing: border-box;
    }
    .postcards-parent-loading-container {
        position: relative;
        top: 60px;
        display: flex;
        justify-content: center;
        align-items: center;
        flex-direction: column;
        width: 100%;
        height: 100vh;
    }
    .cards{
        border-radius: 10px;
        overflow: visible;
        max-width: 100%;
        box-sizing: border-box;
    }
    .card-image-banner{
        max-height: 160px;
        border-radius: 10px 10px 0 0;
    }
    .card-content{
        width: 100%;
        padding: 0.75rem 0.75rem 0.4rem 0.75rem;
        box-sizing: border-box;
    }
    .content-container {
        display: flex;
        flex-direction: column;
        justify-content: flex-start;
        align-items: flex-start;
        user-select: none;
        gap: 0.3rem;
    }
    .feed-title{
        font-size: 0.92rem;
        line-height: 1.3;
    }
    .feed-text-content {
        padding: 0;
        margin: 0;
        font-family: var(--font-serif);
        font-weight: 400;
        font-size: 0.78rem;
        color: var(--text-body);
        line-height: 1.5;
    }
    .canvas-card-actions{
        gap: 0.34rem;
    }
    .canvas-card-action-btn{
        font-size: 0.64rem;
        padding: 0.26rem 0.55rem;
    }

    /* Footer: two explicit rows — author top, actions bottom */
    .card-icons-container{
        display: flex;
        flex-wrap: wrap;
        width: 100%;
        padding: 0.5rem 0.75rem 0.7rem 0.75rem;
        min-height: auto;
        height: auto;
        align-items: center;
        justify-content: flex-start;
        gap: 0.4rem;
        row-gap: 0.5rem;
        box-sizing: border-box;
        overflow: hidden;
    }

    /* Row 1: Author info — full width, forces wrap */
    .card-icons-container .user-info-child-container{
        display: flex;
        align-items: center;
        flex: 0 0 100%;
        gap: 0.3rem;
        padding-bottom: 0.25rem;
        border-bottom: 0.5px solid var(--border-card);
        margin-bottom: 0.1rem;
    }
    .card-icons-container .user-info-child-container .user-newsfeed-name{
        font-family: var(--font-ui);
        font-size: 0.72rem;
        white-space: nowrap;
        overflow: hidden;
        text-overflow: ellipsis;
        max-width: 120px;
    }
    .card-icons-container .user-info-child-container .user-post-date{
        font-family: var(--font-ui);
        font-size: 0.6rem;
        white-space: nowrap;
    }
    .card-icons-container .user-info-child-container .user-info-avatar{
        width: 20px;
        height: 20px;
    }

    /* Row 2: Action icons — guaranteed visible */
    .icon-container{
        display: flex !important;
        align-items: center;
        flex-shrink: 1;
        min-width: 0;
        min-height: 24px;
        visibility: visible;
    }

    /* Base icon button styles (covers like, comment, bookmark) */
    .icon-container .like-button,
    .icon-container .comment-button,
    .icon-container .bookmark-button{
        display: flex;
        justify-content: center;
        align-items: center;
        padding: 0.3rem;
        border-radius: 50%;
        transition: background-color 0.2s ease;
    }

    .svg-like{
        width: 18px !important;
        height: 18px !important;
        display: block;
    }
    .svg-comment{
        width: 18px !important;
        height: 18px !important;
        display: block;
    }
    .svg-bookmark{
        width: 18px !important;
        height: 18px !important;
        display: block;
    }
    #card-icons{
        display: flex;
        align-items: center;
        padding: 0.3rem;
        gap: 0.15rem;
    }
    #card-icons-view{
        display: flex;
        align-items: center;
    }
    #card-icons-view svg{
        width: 22px;
        height: 22px;
    }
    .icon-container p{
        font-family: var(--font-ui);
        font-size: 0.68rem !important;
        white-space: nowrap;
        margin: 0 !important;
        padding: 0 !important;
    }

    /* Reading time pill — always visible, pushed right */
    .reading-time-container{
        display: flex !important;
        visibility: visible;
        margin-left: auto;
        padding: 0.2rem 0.6rem;
        flex-shrink: 0;
        min-width: fit-content;
    }
    .reading-time-text{
        font-size: 0.58rem;
        white-space: nowrap;
    }

    .user-post-settings{
        flex-shrink: 0;
        color: var(--text-heading);
    }
    .user-post-settings svg{
        width: 20px;
        height: 20px;
    }
    .setting-modal{
        right: 0;
        bottom: 25px;
        width: 180px;
        height: 80px;
        font-size: 0.75rem;
    }
    .toolbar {
        display: flex;
        justify-content: center;
        height: 100%;
        width: 100%;
    }
    .toolbar-bttns {
        display: flex;
        width: 16px;
        height: 16px;
        justify-content: center;
        align-items: center;
        padding: 0.5rem;
        border-radius: 10px;
        cursor: pointer;
        transition: ease-in-out 0.1s;
        user-select: none;
    }
    .editor-save-bttn {
        display: flex;
        justify-content: center;
        align-items: center;
        padding: 0.2rem 0.8rem;
        font-size: 0.8rem;
        border-radius: 15px;
        margin-right: 1rem;
        background-color: rgb(255, 255, 255);
        color: rgb(4, 20, 29);
        font-weight: 600;
        cursor: pointer;
        border: hidden;
    }

}
